/**
 * x402 Payment Protocol Types
 *
 * Based on the x402 open standard (https://x402.org)
 * HTTP 402 Payment Required for agent-to-agent micropayments
 */
export interface PaymentTerms {
    amount: string;
    currency: 'USDC' | 'ETH' | 'BASE_ETH';
    network: 'base' | 'ethereum' | 'polygon' | 'solana';
    recipient: string;
    description: string;
    expiresAt: number;
    requestId: string;
}
export interface PaymentProof {
    signature: string;
    payment: {
        requestId: string;
        amount: string;
        currency: string;
        network: string;
        recipient: string;
        payer: string;
        timestamp: number;
    };
    authorization?: {
        from: string;
        to: string;
        value: string;
        validAfter: string;
        validBefore: string;
        nonce: string;
    };
}
export interface ServiceOffering {
    serviceId: string;
    name: string;
    description: string;
    price: PaymentTerms;
    rateLimit: number;
    sensitive: boolean;
}
export interface X402Config {
    enabled: boolean;
    walletAddress?: string;
    maxPaymentPerRequest?: string;
    allowedCurrencies: string[];
    allowedNetworks: string[];
    alchemyApiKey?: string;
    walletKeyPath?: string;
}
export declare const DEFAULT_X402_CONFIG: X402Config;
